const paquetes = {
    basic:{
        nombre: "Básico",
        precio: 500000,
        servicios: ["Sonido", "Decoración básica"]
    },
    medio: {
        nombre: "Medio",
        precio: 1000000,
        servicios: ["Sonido","Decoración profesional","DJ"]
    },
    premium: {
        nombre: "Premium",
        precio:2000000,
        servicios: ["Sonido","Decoración profesional","DJ","Fotografía y vídeo profesional"]
    }
}

const logoBase64 = "data:image/png;base64,"

const recuperarDatos = () => {
    let client = document.getElementById("client").value;
    let event = document.getElementById("event").value;
    let package = document.getElementById("package").value;
    let container = ""
    

    if (client === "" || event === "Seleccione un evento" || package === "Seleccione un paquete"){
        container = "Ingrese un nombre, evento o paquete válido."
    }else{
        procesarCotizacion(client, event, package)
    }
    document.getElementById("container").innerHTML = container
    
}

const procesarCotizacion = (client,event,package) => {
    let datosPaquete = paquetes[package] //linea 23, escoja el paquete que selecciona el user
    let subtotal= datosPaquete.precio
    let iva = subtotal * 0.19
    let total = subtotal + iva 

    let numero = generarNumero()
    let fecha = obtenerFecha()

    generarPDF(client,event,datosPaquete,subtotal,iva,total,numero,fecha)
    
}

const generarNumero = () => {
    return `COT-${Math.floor(Math.random()*10000)}`
}

const obtenerFecha=()=>{
    return new Date().toLocaleDateString()
}

const generarPDF =(client,event,datosPaquete,subtotal,iva,total,numero,fecha)=>{
    const{jsPDF} = window.jspdf
    const doc = new jsPDF()

    //Logo        Fuente   formato   x,y,ancho,alto
    doc.addImage(logoBase64, "PNG", 130,10,50,30)

    //Título
    doc.setFontSize(18)
    doc.text("COTIZACIÓN DE EVENTO",20,20)

    //Info
    doc.setFontSize(11)
    doc.text(`Número: ${numero}`,20,30)
    doc.text(`Fecha: ${fecha}`,20,40)
    
    doc.text(`Cliente: ${client}`,20,50)
    doc.text(`Evento: ${event}`,20,60)
    doc.text(`Paquete: ${datosPaquete.nombre}`,20,70)

    //tabla de servicios
    let serviciosTabla = []

    for(let i=0; i < datosPaquete.servicios.length; i++){
        serviciosTabla.push([datosPaquete.servicios[i]])
    }

    doc.autoTable({
        startY: 65,
        head:[["Servicios incluídos"]],
        body: serviciosTabla

    })

    //Totales
    let y = doc.lastAutoTable.finalY + 10

    doc.text(`Subtotal: $${subtotal}`,20, y)
    doc.text(`Iva(19%): $${iva}`,20, y +6)
    doc.text(`Total: $${total}`,20, y +12)


    //Pie
    doc.text("Gracias por confiar en nosotros. Información al xxx",20, y + 25)


    doc.save(`Cotización_${numero}`)


}



